import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';
import { GoogleLogin } from '@react-oauth/google';

const StudentLogin = () => {
  const { login, googleLogin, googleRegister } = useContext(AuthContext);
  const navigate = useNavigate();

  const [formData, setFormData] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  // Google Registration State
  const [requiresRegistration, setRequiresRegistration] = useState(false);
  const [registrationData, setRegistrationData] = useState({
    role: 'student',
    subject: '',
    googleToken: '',
    name: '',
    email: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    if (requiresRegistration) {
      setRegistrationData((prev) => ({ ...prev, [name]: value }));
    } else {
      setFormData((prev) => ({ ...prev, [name]: value }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await login({ ...formData, role: 'student' });
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSuccess = async (credentialResponse) => {
    setError('');
    setLoading(true);

    try {
      const res = await googleLogin({ token: credentialResponse.credential, role: 'student' });

      if (res?.requiresRegistration) {
        setRequiresRegistration(true);
        setRegistrationData((prev) => ({
          ...prev,
          googleToken: res.googleToken,
          name: res.name,
          email: res.email,
        }));
      } else {
        navigate('/dashboard');
      }
    } catch (err) {
      setError(err.response?.data?.error || 'Google Login failed');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleError = () => {
    setError('Google Login failed completely.');
  };

  const handleGoogleRegisterSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      await googleRegister(registrationData);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Google Registration failed');
    } finally {
      setLoading(false);
    }
  };

  if (requiresRegistration) {
    return (
      <div className="min-vh-100 d-flex align-items-center student-login-shell">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-md-6 col-lg-5">
              <div className="card shadow-lg border-0 student-login-card">
                <div className="card-body p-5">
                  <div className="text-center mb-4">
                    <span className="student-login-badge">Complete Profile</span>
                    <h2 className="card-title fw-bold mt-3 mb-2">Welcome, {registrationData.name.split(' ')[0]}!</h2>
                    <p className="text-muted mb-0">
                      Please complete your profile to finish creating your account.
                    </p>
                  </div>

                  {error && (
                    <div className="alert alert-danger alert-dismissible fade show" role="alert">
                      {error}
                      <button type="button" className="btn-close" onClick={() => setError('')}></button>
                    </div>
                  )}

                  <form onSubmit={handleGoogleRegisterSubmit}>
                    <div className="mb-3">
                      <label htmlFor="role" className="form-label">I am a...</label>
                      <select
                        className="form-select student-login-input"
                        id="role"
                        name="role"
                        value={registrationData.role}
                        onChange={handleChange}
                        required
                      >
                        <option value="student">Student</option>
                        <option value="staff">Staff / Guide</option>
                      </select>
                    </div>

                    {registrationData.role === 'staff' && (
                      <div className="mb-3">
                        <label htmlFor="subject" className="form-label">Department / Subject</label>
                        <input
                          type="text"
                          className="form-control student-login-input"
                          id="subject"
                          name="subject"
                          value={registrationData.subject}
                          onChange={handleChange}
                          required
                          placeholder="e.g. Computer Science"
                        />
                      </div>
                    )}

                    <button type="submit" className="btn btn-primary w-100 fw-bold student-login-button" disabled={loading}>
                      {loading ? (
                        <><span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>Saving...</>
                      ) : (
                        'Complete Registration'
                      )}
                    </button>
                    <div className="mt-3 text-center">
                      <button type="button" className="btn btn-link text-muted text-decoration-none" onClick={() => setRequiresRegistration(false)}>
                        Cancel
                      </button>
                    </div>
                  </form>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-vh-100 d-flex align-items-center student-login-shell">
      <div className="container">
        <div className="row justify-content-center">
          <div className="col-md-6 col-lg-5">
            <div className="card shadow-lg border-0 student-login-card">
              <div className="card-body p-5">
                <div className="text-center mb-4">
                  <span className="student-login-badge">AskDesk</span>
                  <h2 className="card-title fw-bold mt-3 mb-2">AskDesk Login</h2>
                  <p className="text-muted mb-0">
                    Access your dashboard and manage academic doubt resolution.
                  </p>
                </div>

                {error && (
                  <div className="alert alert-danger alert-dismissible fade show" role="alert">
                    {error}
                    <button
                      type="button"
                      className="btn-close"
                      onClick={() => setError('')}
                    ></button>
                  </div>
                )}

                <form onSubmit={handleSubmit}>
                  <div className="mb-3">
                    <label htmlFor="email" className="form-label">
                      Email Address
                    </label>
                    <input
                      type="email"
                      className="form-control student-login-input"
                      id="email"
                      name="email"
                      value={formData.email}
                      onChange={handleChange}
                      required
                      placeholder="your@email.com"
                    />
                  </div>

                  <div className="mb-3">
                    <label htmlFor="password" className="form-label">
                      Password
                    </label>
                    <input
                      type="password"
                      className="form-control student-login-input"
                      id="password"
                      name="password"
                      value={formData.password}
                      onChange={handleChange}
                      required
                      placeholder="Enter your password"
                    />
                  </div>

                  <button
                    type="submit"
                    className="btn btn-primary w-100 fw-bold student-login-button"
                    disabled={loading}
                  >
                    {loading ? (
                      <>
                        <span
                          className="spinner-border spinner-border-sm me-2"
                          role="status"
                          aria-hidden="true"
                        ></span>
                        Logging in...
                      </>
                    ) : (
                      'Login'
                    )}
                  </button>

                  <div className="d-flex justify-content-center mt-3 position-relative">
                    <hr className="w-100" />
                    <span className="position-absolute bg-white px-2 text-muted" style={{ top: '-10px', left: '50%', transform: 'translateX(-50%)' }}>or</span>
                  </div>

                  <div className="d-flex justify-content-center mt-3">
                    <GoogleLogin
                      onSuccess={handleGoogleSuccess}
                      onError={handleGoogleError}
                      useOneTap
                      theme="filled_blue"
                      shape="pill"
                    />
                  </div>
                </form>

                <div className="text-center mt-4">
                  <p className="text-muted">
                    Don't have an account?{' '}
                    <a href="/register" className="student-login-link fw-bold text-decoration-none">
                      Register here
                    </a>
                  </p>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default StudentLogin;
